import { Component } from "react";
import RedesSociales from './RedesSociales'
import TituloSeccion from './TituloSeccion'

const redesSociales = [
    {nombre: 'Github', enlace: 'https://github.com/TheJhoxX', img: '/githubLogo.svg'},
    {nombre: 'Linkedin', enlace: 'https://www.linkedin.com/in/victor-jorge-sibaja-156899196', img: '/linkedinLogo.svg'}
]

class Seccion extends Component {
    render() {
        const { nombre } = this.props
        return( 
            <div id={nombre} className="seccion-portfolio">
                <TituloSeccion nombre={nombre} />
                {nombre === 'Redes sociales'
                ?   <RedesSociales redesSociales={redesSociales}/>
                :   null}
            </div>
        )
    }
}

export default Seccion
